package main

import (
	"fmt"
	"strings"
)

func isSubsequence(s string, t string) bool {
	// find all the characters of s in t
	candidates := make([]rune, 0, len(t))
	for _, v := range t {
		if strings.Contains(s, string(v)) {
			candidates = append(candidates, v)
		}
	}

	// convert subsequnce to a list of runes
	subsequences := make([]rune, 0, len(s))
	for _, i := range s {
		subsequences = append(subsequences, i)
	}

	idx, output := 0, ""
	for idx < len(s) {
		// if candidates is less than idx
		// if candidates is less than len(s)
		// ==> candidates is not a subsequence of s
		if len(candidates) < idx {
			break
		}
		if len(candidates) < len(s) {
			break
		}

		// condition 1:
		// s=abc,t=cabc
		// ==> skip c, so remove c from candidates
		if idx == 0 && subsequences[idx] != candidates[idx] {
			candidates = append(candidates[:idx], candidates[idx+1:]...)
			continue
		}

		// suitable condition:
		// s=abc,t=abc
		// ==> add a to output, so remove a from candidates
		// ------
		// condition 2: (else if part)
		// s=abc,t=abbc
		// ==> skip b, so remove b from candidates
		// ------
		// condition 3:
		// s=abc,t=acb
		// ==> not suitable, so break
		if subsequences[idx] == candidates[idx] {
			output += string(candidates[idx])
			idx += 1
			continue
		} else if idx > 0 && candidates[idx] == subsequences[idx-1] {
			candidates = append(candidates[:idx], candidates[idx+1:]...)
			continue
		} else {
			break
		}
	}

	return output == s
}

func main() {
	fmt.Println(isSubsequence("abc", "ahbgdc"))
	fmt.Println(isSubsequence("axc", "ahbgdc"))
	fmt.Println(isSubsequence("leeeeetcode", ""))
	fmt.Println(isSubsequence("rjufvjafbxnbgriwgokdgqdqewn", ""))
}
